const commits = $('Fetch Commits').item.json;
const deploys = $('Fetch Deploy Runs').item.json;
const errors = $('Fetch Error Summary').item.json;
const usage = $('Fetch Usage Stats').item.json;

const repo = process.env.GITHUB_REPO || 'iansduncan-oss/ai-cofounder';

// --- 1. Commits grouped by conventional prefix ---
const commitList = Array.isArray(commits) ? commits : [];
const grouped = {};
for (const c of commitList) {
  const msg = c.commit?.message?.split('\n')[0] || 'Unknown';
  const match = msg.match(/^(\w+)[(!:]/);
  const prefix = match ? match[1] : 'other';
  if (!grouped[prefix]) grouped[prefix] = [];
  grouped[prefix].push(msg);
}

const commitLines = [];
const prefixOrder = ['feat', 'fix', 'refactor', 'chore', 'docs', 'test', 'ci', 'other'];
for (const prefix of prefixOrder) {
  if (grouped[prefix] && grouped[prefix].length > 0) {
    commitLines.push(`**${prefix}** (${grouped[prefix].length})`);
    grouped[prefix].slice(0, 5).forEach(m => commitLines.push(`  • ${m}`));
    if (grouped[prefix].length > 5) commitLines.push(`  • ... and ${grouped[prefix].length - 5} more`);
    delete grouped[prefix];
  }
}
for (const [prefix, msgs] of Object.entries(grouped)) {
  if (msgs.length > 0) {
    commitLines.push(`**${prefix}** (${msgs.length})`);
    msgs.slice(0, 3).forEach(m => commitLines.push(`  • ${m}`));
    if (msgs.length > 3) commitLines.push(`  • ... and ${msgs.length - 3} more`);
  }
}
if (commitLines.length === 0) commitLines.push('No commits this week');

// --- 2. Deploy stats ---
const runs = deploys.workflow_runs || [];
const totalRuns = runs.length;
const successRuns = runs.filter(r => r.conclusion === 'success').length;
const failedRuns = runs.filter(r => r.conclusion === 'failure').length;
const successRate = totalRuns > 0 ? ((successRuns / totalRuns) * 100).toFixed(1) : '0';

// --- 3. Errors ---
const errorList = errors.errors || errors.summary || [];
const totalErrors = errors.totalErrors || errors.total || 0;
const errorLines = [];
if (totalErrors > 0) {
  errorLines.push(`**${totalErrors}** total errors`);
  errorList.slice(0, 5).forEach(e => {
    errorLines.push(`  • ${e.message || e.error || 'Unknown'} (×${e.count || 1})`);
  });
} else {
  errorLines.push('No errors this week 🎉');
}

// --- 4. Cost summary ---
const totalTokens = (usage.totalInputTokens || 0) + (usage.totalOutputTokens || 0);
const totalCost = ((usage.totalCostMicrodollars || 0) / 1_000_000).toFixed(2);
const requestCount = usage.requestCount || 0;
const models = usage.byModel || [];
const modelLines = models.slice(0, 5).map(m => {
  const cost = (m.costMicrodollars / 1_000_000).toFixed(4);
  return `  • **${m.model}**: ${m.requests} req, $${cost}`;
});

// --- Compare link ---
const weekAgo = new Date(Date.now() - 7 * 86400000).toISOString().split('T')[0];
const today = new Date().toISOString().split('T')[0];

// --- Build embed ---
const embed = {
  title: '📊 Weekly Digest',
  color: 3447003,
  timestamp: new Date().toISOString(),
  fields: [
    { name: `📝 Commits (${commitList.length})`, value: commitLines.join('\n').substring(0, 1024), inline: false },
    { name: '🚀 Deploys', value: `${totalRuns} runs: ${successRuns} ✅ ${failedRuns} ❌ — **${successRate}%** success rate`, inline: false },
    { name: '🐛 Errors (7d)', value: errorLines.join('\n').substring(0, 1024), inline: false },
    { name: '💰 Cost', value: `**$${totalCost}** | ${requestCount.toLocaleString()} requests | ${totalTokens.toLocaleString()} tokens`, inline: false },
  ],
  footer: { text: `Week of ${weekAgo} to ${today}` },
};

if (modelLines.length > 0) {
  embed.fields.push({ name: '📈 By Model', value: modelLines.join('\n'), inline: false });
}

// Compare link
embed.fields.push({ name: '🔗 Links', value: `[GitHub Compare](https://github.com/${repo}/compare/main@{${weekAgo}}...main@{${today}})`, inline: false });

// Slack-compatible text version
const slackText = [
  '*📊 Weekly Digest*',
  `*Commits:* ${commitList.length} | *Deploys:* ${totalRuns} (${successRate}% success) | *Errors:* ${totalErrors} | *Cost:* $${totalCost}`,
  `<https://github.com/${repo}/compare/main@{${weekAgo}}...main@{${today}}|View on GitHub>`,
].join('\n');

return [{ json: { embed, slackText } }];
